// Validar X-Conferente-Signature HMAC-SHA256
const crypto = require('crypto');
const body = JSON.stringify($input.first().json.body);
const signature = $input.first().json.headers['x-conferente-signature'];
const expected = 'sha256=' + crypto.createHmac('sha256', $env.CONFERENTE_SECRET).update(body).digest('hex');
if (signature !== expected) throw new Error('HMAC inválido');
return $input.all();

// Monta mensagem para LLM com system prompt da persona SEG
// SUBSTITUIR pelo prompt real da v1 (gca-personas-system-prompts.md §3.4 — seguranca)
const systemPrompt = `PROMPT_SEGURANCA

Você é o especialista em Segurança (SEG) do pipeline GCA.

Seu papel é analisar o documento sob a ótica de segurança:
1. **OWASP Top 10**: Vulnerabilidades comuns identificáveis (injection, XSS, CSRF, etc.)
2. **Secrets**: Credenciais, tokens ou dados sensíveis expostos no documento?
3. **AuthN/AuthZ**: Autenticação e autorização bem definidas e seguras?
4. **Criptografia**: Dados em repouso e em trânsito protegidos?
5. **Dependências**: Bibliotecas com CVEs conhecidos?
6. **Superfície de ataque**: API, endpoints, ingressos externos auditados?

SEUS OUTPUTS OBRIGATÓRIOS (em UMA resposta JSON):

1. SCORES (0–100)
   - owasp: cobertura de vulnerabilidades OWASP
   - secrets: ausência de exposição de credenciais
   - authn_authz: qualidade de autenticação e autorização
   - criptografia: proteção de dados
   - dependencias: segurança de dependências

2. APPROVED (bool): true se o documento não apresenta riscos críticos de segurança

3. ISSUES (array): vulnerabilidades e riscos identificados

4. QUESTIONS (array): perguntas necessárias para avaliação completa

5. JUSTIFICATION (texto): raciocínio resumido

Sem improviso. Se não houver insumo suficiente, declare incerteza explícita.

RETORNE APENAS JSON VÁLIDO (sem markdown, sem \`\`\`).`;
const input = $input.first().json;
const userMessage = `Documento: ${input.body.document_text}\n\nContexto compartilhado: ${JSON.stringify(input.body.shared_context)}`;

// Resolver provider da chain
const chain = input.body.provider_chain || [];
const provider = chain[0] || {provider: 'deepseek', model: 'deepseek-v4-pro'};

return [{json: {systemPrompt, userMessage, provider, ingestion_id: input.body.ingestion_id, project_id: input.body.project_id, started_at: new Date().toISOString()}}];

// Parse resposta LLM e montar PersonaOutput
const input = $('Montar prompt').first().json;
const llmResponse = $input.first().json;
const content = llmResponse.content?.[0]?.text || llmResponse.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {}; }

const scores = parsed.SCORES || {};
const scoreValues = Object.values(scores).filter(v => typeof v === 'number');
const avgScore = scoreValues.length > 0 ? Math.round(scoreValues.reduce((a,b) => a+b, 0) / scoreValues.length) : 50;

const output = {
  schema_version: 'PersonaOutput-v2',
  ingestion_id: input.ingestion_id,
  persona_tag: 'SEG',
  persona_name: 'Segurança',
  execution_metadata: {
    started_at: input.started_at,
    completed_at: new Date().toISOString(),
    model_used: input.provider.model,
    tokens_consumed: {input: llmResponse.usage?.prompt_tokens || llmResponse.usage?.input_tokens || 0, output: llmResponse.usage?.completion_tokens || llmResponse.usage?.output_tokens || 0}
  },
  score: avgScore,
  score_rationale: (parsed.JUSTIFICATION || '').substring(0, 280),
  blocking: false,
  blocking_reason: null,
  status: 'completed',
  findings: (parsed.ISSUES || []).map((issue, i) => ({id: `finding-${i}`, severity: 'high', category: 'seguranca', title: typeof issue === 'string' ? issue.substring(0, 120) : (issue.description || '').substring(0, 120), description: typeof issue === 'string' ? issue : (issue.description || '')})),
  recommendations: [],
  ocg_contributions: {individual: scores, global_delta: {}},
  validation_self_report: {schema_version_check: true, score_in_range: true, evidence_excerpts_present: false, ocg_individual_non_empty: true, ocg_global_delta_non_empty: false}
};

return [{json: output}];
